    if (initialPointsSet.any { it.contentToString() == targetKey }) {
        return 0
    }

    // Set to store all unique points generated so far (up to the current generation)
    var currentPointsSet = initialPointsSet.toMutableSet()

    // List to store all unique points generated up to the previous generation's end
    // This list is used to form the set of "available points" for the next generation.
    var availablePoints = initialPointsList.toMutableList()

    var k = 0
    val maxK = 1000 // A reasonable upper bound, given the constraints and nature of the problem

    while (k < maxK) {
        k++
        val newPoints = mutableSetOf<String>()

        // Generate points for the k-th generation
        // We pair every distinct point from the currently available set (availablePoints)
        val availableList = availablePoints.distinct() // Ensure we only iterate over unique coordinates
        val n = availableList.size

        if (n < 2) {
            // Cannot form any new points if there are less than 2 distinct available points
            break
        }

        for (i in 0 until n) {
            for (j in i + 1 until n) {
                val p1 = availableList[i]
                val p2 = availableList[j]

                // Calculate the midpoint c = [floor((x1 + x2) / 2), ...]
                val cx = floor((p1[0] + p2[0]) / 2.0).toLong()
                val cy = floor((p1[1] + p2[1]) / 2.0).toLong()
