                val newPointKey = newPoint.contentToString()

                if (!currentPointsSet.contains(newPointKey)) {
                    newPoints.add(newPointKey)
                }
            }
        }

        // Convert new point keys back to array representation for tracking
        val generatedPoints = newPoints.map { 
            it.substring(1, it.length - 1).split(", ").map { it.toLong() }.toLongArray() 
        }.toTypedArray()

        // Update current set and available list for the next iteration
        currentPointsSet.addAll(newPoints)

        // Add newly generated unique points to the list of available points for the next generation
        // This is crucial: "the k-th generation points are considered available for forming later generations."
